import type { Event } from "@trace/gql";
import { useEntityStore, eventScopeKey } from "../stores/entity";
import { useAuthStore } from "../stores/auth";

const OPTIMISTIC_PREFIX = "optimistic:";

/** Returns true if the event ID was generated by an optimistic insert */
export function isOptimisticEvent(id: string): boolean {
  return id.startsWith(OPTIMISTIC_PREFIX);
}

/**
 * Insert an optimistic `message_sent` event into the session's scoped
 * event bucket so it appears instantly in the session log.
 *
 * Returns the temp event ID for later cleanup.
 */
export function optimisticallyInsertSessionMessage(
  sessionId: string,
  text: string,
): string {
  const user = useAuthStore.getState().user;
  const now = new Date().toISOString();
  const tempId = `${OPTIMISTIC_PREFIX}${crypto.randomUUID()}`;
  const scopeKey = eventScopeKey("session", sessionId);

  const event: Event = {
    id: tempId,
    scopeType: "session",
    scopeId: sessionId,
    eventType: "message_sent",
    payload: { text } as unknown as Record<string, unknown>,
    actor: {
      type: "user",
      id: user?.id ?? "",
      name: user?.name ?? null,
      avatarUrl: user?.avatarUrl ?? null,
    },
    parentId: null,
    timestamp: now,
    metadata: null,
  };

  useEntityStore.getState().upsertScopedEvent(scopeKey, tempId, event);
  return tempId;
}

/**
 * Remove an optimistic event from the session's scoped event bucket.
 * Called when the real event arrives via subscription or on mutation failure.
 */
export function removeOptimisticSessionMessage(
  sessionId: string,
  tempEventId: string,
): void {
  const scopeKey = eventScopeKey("session", sessionId);
  const store = useEntityStore.getState();
  const bucket = store.eventsByScope[scopeKey];
  if (!bucket || !bucket[tempEventId]) return;

  // Remove by creating a new bucket without the temp event
  const { [tempEventId]: _, ...rest } = bucket;
  useEntityStore.setState((state) => ({
    eventsByScope: {
      ...state.eventsByScope,
      [scopeKey]: rest,
    },
  }));
}

/**
 * Insert an optimistic chat message into the messages table and
 * a corresponding event into the chat's scoped event bucket.
 *
 * Returns the temp event ID for later cleanup.
 */
export function optimisticallyInsertChatMessage(
  chatId: string,
  html: string,
  parentId?: string | null,
): string {
  const user = useAuthStore.getState().user;
  const now = new Date().toISOString();
  const tempEventId = `${OPTIMISTIC_PREFIX}${crypto.randomUUID()}`;
  const tempMessageId = `${OPTIMISTIC_PREFIX}${crypto.randomUUID()}`;
  const scopeKey = eventScopeKey("chat", chatId);

  const actor = {
    type: "user" as const,
    id: user?.id ?? "",
    name: user?.name ?? null,
    avatarUrl: user?.avatarUrl ?? null,
  };

  // Insert message entity
  useEntityStore.getState().upsert("messages", tempMessageId, {
    id: tempMessageId,
    chatId,
    channelId: null,
    text: html,
    html,
    mentions: null,
    parentMessageId: parentId ?? null,
    replyCount: 0,
    latestReplyAt: null,
    threadRepliers: [],
    actor,
    createdAt: now,
    updatedAt: now,
    editedAt: null,
    deletedAt: null,
  });

  // Insert scoped event
  const event: Event = {
    id: tempEventId,
    scopeType: "chat",
    scopeId: chatId,
    eventType: "message_sent",
    payload: { messageId: tempMessageId, text: html, html } as unknown as Record<string, unknown>,
    actor,
    parentId: null,
    timestamp: now,
    metadata: null,
  };

  useEntityStore.getState().upsertScopedEvent(scopeKey, tempEventId, event);
  return tempMessageId;
}

/**
 * Remove an optimistic chat message when the real one arrives.
 */
export function removeOptimisticChatMessage(
  chatId: string,
  tempMessageId: string,
): void {
  const store = useEntityStore.getState();
  store.remove("messages", tempMessageId);

  // Also remove the corresponding event from the scoped bucket
  const scopeKey = eventScopeKey("chat", chatId);
  const bucket = store.eventsByScope[scopeKey];
  if (!bucket) return;

  // Find event that references this message
  const tempEventId = Object.keys(bucket).find((id) => {
    if (!id.startsWith(OPTIMISTIC_PREFIX)) return false;
    const payload = bucket[id].payload as Record<string, unknown> | null;
    return payload?.messageId === tempMessageId;
  });

  if (tempEventId) {
    const { [tempEventId]: _, ...rest } = bucket;
    useEntityStore.setState((state) => ({
      eventsByScope: {
        ...state.eventsByScope,
        [scopeKey]: rest,
      },
    }));
  }
}
